const items = $input.all();

// Alle Artikel mit Datum parsen
const articles = items.map(item => {
  const d = item.json;
  const dateStr = d.pubDate || d.isoDate || d.date || d.published || '';
  const ts = dateStr ? new Date(dateStr).getTime() : 0;
  return {
    title: d.title || '',
    summary: d.contentSnippet || d.content || d.summary || d.description || '',
    link: d.link || d.guid || '',
    date: dateStr,
    timestamp: ts,
    source: d.meta?.title || d.feedUrl || 'Unbekannt'
  };
}).filter(a => a.title && a.timestamp > 0);

// Nach Datum sortieren — neuester zuerst
articles.sort((a, b) => b.timestamp - a.timestamp);

// Top 5 nehmen und als Kontext zusammenfassen
const top5 = articles.slice(0, 5);
const context = top5.map((a, i) =>
  `[${i+1}] ${a.title}\nQuelle: ${a.source}\nDatum: ${a.date}\nLink: ${a.link}\nZusammenfassung: ${a.summary.slice(0, 400)}`
).join('\n\n---\n\n');

return [{ json: { context, top5 } }];

const { context, top5 } = $input.first().json;
const today = new Date().toISOString().split('T')[0];
const bestArticle = top5[0];

const prompt = `Du bist ein professioneller IT-Sicherheitsjournalist fuer sicherheit.ai, ein deutsches Cybersecurity-Portal.

Hier sind die aktuellsten Security-News der letzten 24 Stunden aus verschiedenen Quellen:

${context}

Waehle das wichtigste und relevanteste Thema fuer ein deutsches Publikum aus und schreibe daraus einen vollstaendigen Blog-Post auf Deutsch.

HEUTIGES DATUM: ${today}
HAUPT-QUELLE-LINK: ${bestArticle.link}
HAUPT-QUELLE-TITEL: ${bestArticle.source}

ANTWORTE NUR MIT PUREM JSON — kein Markdown, keine Backticks, kein Text davor oder danach.

JSON-Struktur (alle Felder sind Pflicht):
{
  "slug": "nur-kleinbuchstaben-und-bindestriche-max-60-zeichen",
  "title": "Titel maximal 80 Zeichen sachlich und informativ",
  "excerpt": "Genau zwei Saetze als Teaser. Konkrete Fakten. Maximal 200 Zeichen.",
  "content": "Vollstaendiger HTML-Artikel. Mindestens 700 Woerter. Nutze diese Struktur: <h2 id='was-passiert'>Was ist passiert?</h2><p>Konkreter Sachverhalt mit Firmennamen, Zahlen, Daten, betroffene Systeme.</p><h2 id='hintergrund'>Technischer Hintergrund</h2><p>Erklaerung fuer Fachleute und Einsteiger.</p><h2 id='auswirkungen'>Auswirkungen fuer deutsche Unternehmen</h2><p>Was bedeutet das konkret fuer deutsche Firmen und Nutzer?</p><h2 id='massnahmen'>Empfohlene Massnahmen</h2><p>Konkrete Schritte die Admins und Nutzer jetzt tun sollten. Nummerierte Liste wenn moeglich.</p>",
  "category": "KATEGORIE",
  "categoryColor": "#FARBE",
  "categoryBg": "rgba(r,g,b,0.1)",
  "author": "sicherheit.ai Redaktion",
  "authorRole": "Automatisch recherchiert & KI-redigiert",
  "publishedAt": "${today}",
  "readTime": 8,
  "imageGradient": "GRADIENT",
  "badge": null,
  "badgeColor": null,
  "tags": ["tag1", "tag2", "tag3", "tag4"],
  "faqs": [
    {"q": "Konkrete relevante Frage zum Thema?", "a": "Vollstaendige hilfreiche Antwort in 2-3 Saetzen."},
    {"q": "Was sollte ich jetzt sofort tun?", "a": "Konkrete Handlungsempfehlung."},
    {"q": "Bin ich als Privatnutzer auch betroffen?", "a": "Ehrliche Einschaetzung."}
  ],
  "sources": [
    {"title": "${bestArticle.source}", "url": "${bestArticle.link}"}
  ]
}

Kategorie-Tabelle (waehle exakt eine):
- CVE / Patch / Luecke → category="Schwachstelle", categoryColor="#FF9632", categoryBg="rgba(255,150,50,0.1)", imageGradient="linear-gradient(135deg, #1A0800 0%, #2A1200 40%, #1A0800 100%)"
- Hack / Datenpanne / Ransomware → category="Incident", categoryColor="#FF2D6F", categoryBg="rgba(255,45,111,0.1)", imageGradient="linear-gradient(135deg, #1A0010 0%, #2A0020 40%, #1A0010 100%)"
- Gesetz / NIS2 / DSGVO / AI Act → category="Regulierung", categoryColor="#7890FF", categoryBg="rgba(100,120,255,0.12)", imageGradient="linear-gradient(135deg, #060B18 0%, #0A1230 40%, #060B18 100%)"
- KI / LLM / Machine Learning → category="KI-Sicherheit", categoryColor="#00F0FF", categoryBg="rgba(0,240,255,0.1)", imageGradient="linear-gradient(135deg, #001A1A 0%, #003333 40%, #001A1A 100%)"
- APT / Nation-State / Spionage → category="Bedrohung", categoryColor="#FF2D6F", categoryBg="rgba(255,45,111,0.1)", imageGradient="linear-gradient(135deg, #1A0010 0%, #2A0020 40%, #1A0010 100%)"
- Studie / Bericht / Statistik → category="Analyse", categoryColor="#9664FF", categoryBg="rgba(150,100,255,0.1)", imageGradient="linear-gradient(135deg, #0D0820 0%, #1A1030 40%, #0D0820 100%)"
- Allgemeine Tech-Security-News → category="News", categoryColor="#78C864", categoryBg="rgba(120,200,100,0.1)", imageGradient="linear-gradient(135deg, #060E08 0%, #0A1A0E 40%, #060E08 100%)"

Bei kritischer CVE: badge="CVSS 9.x" und badgeColor="#FF2D6F" setzen, sonst beide null lassen.`;

const body = {
  model: "claude-sonnet-4-6",
  max_tokens: 4000,
  messages: [{ role: "user", content: prompt }]
};

return [{ json: { body: JSON.stringify(body) } }];

const raw = $input.first().json.content[0].text;

let clean = raw.trim();

// Markdown-Wrapper entfernen
if (clean.startsWith('```json')) {
  clean = clean.replace(/^```json\s*/, '').replace(/\s*```$/, '').trim();
} else if (clean.startsWith('```')) {
  clean = clean.replace(/^```\s*/, '').replace(/\s*```$/, '').trim();
}

// Falls Text vor JSON steht
if (!clean.startsWith('{')) {
  const match = clean.match(/\{[\s\S]*\}/);
  if (match) clean = match[0];
}

let post;
try {
  post = JSON.parse(clean);
} catch(e) {
  throw new Error('JSON Parse Fehler: ' + e.message + '\n\nText: ' + clean.slice(0, 500));
}

// Pflichtfelder sicherstellen
post.id = Date.now().toString();
post.publishedAt = post.publishedAt || new Date().toISOString().split('T')[0];
post.author = post.author || 'sicherheit.ai Redaktion';
post.authorRole = post.authorRole || 'Automatisch recherchiert & KI-redigiert';
post.tags = Array.isArray(post.tags) ? post.tags : [];
post.faqs = Array.isArray(post.faqs) ? post.faqs : [];
post.sources = Array.isArray(post.sources) ? post.sources : [];
post.readTime = Number(post.readTime) || 8;

// Leere null-Felder entfernen
if (!post.badge) delete post.badge;
if (!post.badgeColor) delete post.badgeColor;
if (!post.imageAlt) delete post.imageAlt;

return [{ json: post }];

const fileData = $('GitHub Datei laden').first().json;
const sha = fileData.sha;

// GitHub Base64 mit Zeilenumbruechen bereinigen
const base64Clean = fileData.content.replace(/\n/g, '');
const currentJson = Buffer.from(base64Clean, 'base64').toString('utf8');
let posts = JSON.parse(currentJson);

const newPost = $('Response parsen').first().json;

// Duplikat-Schutz
const exists = posts.some(p => p.slug === newPost.slug);
if (!exists) {
  posts.unshift(newPost);
}

// Max 100 Posts in der Datei
posts = posts.slice(0, 100);

const updatedBase64 = Buffer.from(JSON.stringify(posts, null, 2)).toString('base64');

return [{
  json: {
    sha,
    updatedBase64,
    postTitle: newPost.title,
    postSlug: newPost.slug,
    totalPosts: posts.length
  }
}];
